def make_request_cache_key(
    prefix: str = "api-cache",
    include_headers: Tuple[str, ...] = (),
    include_query: bool = True,
    include_body: bool = True,
) -> str:
    parts = [prefix, request.method, request.path]

    if include_query:
        args = sorted((k, request.args.getlist(k)) for k in request.args.keys())
        parts.append(repr(args))

    if include_headers:
        hdrs = []
        for h in include_headers:
            v = request.headers.get(h)
            hdrs.append((h.lower(), v))
        parts.append(repr(hdrs))

    if include_body and request.method in ("POST", "PUT", "PATCH"):
        body = request.get_data(cache=False, as_text=False) or b""
        parts.append(hashlib.sha256(body).hexdigest())

    return "|".join(parts)


def cached_json(
    cache: DiskCache,
    key_func: Callable[[], str],
    compute_func: Callable[[], Dict[str, Any]],
    ttl: Optional[int] = None,
    metadata_func: Optional[Callable[[], Dict[str, Any]]] = None,
) -> Response:
    key = key_func()
    entry = cache.get(key)
    if entry is not None:
        resp = jsonify(entry.payload)
        resp.headers["X-Cache"] = "HIT"
        resp.headers["X-Cache-Expires-At"] = str(int(entry.expires_at))
        return resp

    payload = compute_func()
    metadata = metadata_func() if metadata_func else None
    entry = cache.set(key, payload, ttl=ttl, metadata=metadata)

    resp = jsonify(payload)
    resp.headers["X-Cache"] = "MISS"
    resp.headers["X-Cache-Expires-At"] = str(int(entry.expires_at))
    return resp


